import scala.util.Random
import java.time.Instant
import scala.collection.concurrent.TrieMap

case class SessionToken(
  token: String,
  createdAt: Instant,
  expiresAt: Instant,
  userId: String
)

case class ApiKey(
  key: String,
  createdAt: Instant,
  name: String,
  userId: String
)

class TokenGenerationService(
  sessionExpirationSeconds: Long = 3600,
  random: Random = new Random()
) {

  private val activeSessions = TrieMap.empty[String, SessionToken]
  private val apiKeys = TrieMap.empty[String, ApiKey]

  def generateSessionToken(userId: String): SessionToken = {
    val token = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    val expiresAt = now.plusSeconds(sessionExpirationSeconds)
    
    val sessionToken = SessionToken(
      token = token,
      createdAt = now,
      expiresAt = expiresAt,
      userId = userId
    )
    
    activeSessions.put(token, sessionToken)
    sessionToken
  }

  def generateApiKey(userId: String, name: String): ApiKey = {
    val key = random.alphanumeric.take(32).mkString
    val now = Instant.now()
    
    val apiKey = ApiKey(
      key = key,
      createdAt = now,
      name = name,
      userId = userId
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }

  def validateSessionToken(token: String): Option[SessionToken] = {
    activeSessions.get(token).filter { session =>
      Instant.now().isBefore(session.expiresAt)
    }
  }

  def validateApiKey(key: String): Option[ApiKey] = {
    apiKeys.get(key)
  }

  def invalidateSessionToken(token: String): Boolean = {
    activeSessions.remove(token).isDefined
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeys.remove(key).isDefined
  }

  def refreshSessionToken(token: String): Option[SessionToken] = {
    validateSessionToken(token).map { session =>
      invalidateSessionToken(token)
      generateSessionToken(session.userId)
    }
  }

  def getActiveSessionsForUser(userId: String): List[SessionToken] = {
    activeSessions.values.filter(_.userId == userId).toList
  }

  def getApiKeysForUser(userId: String): List[ApiKey] = {
    apiKeys.values.filter(_.userId == userId).toList
  }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = activeSessions.filter { case (_, session) =>
      now.isAfter(session.expiresAt)
    }
    expired.foreach { case (token, _) =>
      activeSessions.remove(token)
    }
    expired.size
  }

  def generateSecureToken(length: Int = 32): String = {
    random.alphanumeric.take(length).mkString
  }

  def generateNumericCode(length: Int = 6): String = {
    (1 to length).map(_ => random.nextInt(10)).mkString
  }

  def getTotalActiveSessions: Int = activeSessions.size

  def getTotalApiKeys: Int = apiKeys.size
}

object TokenGenerationService {
  def apply(): TokenGenerationService = new TokenGenerationService()
  
  def apply(sessionExpirationSeconds: Long): TokenGenerationService = 
    new TokenGenerationService(sessionExpirationSeconds)
}